questionvariables.text:
/* 1. Define a simple triangle in the first quadrant */
x1: 2 + rand(3); y1: 2 + rand(3);
x2: x1 + 2;      y2: y1;
x3: x1;          y3: y1 + 2;

/* 2. Define a negative scale factor */
sf: -1 * (1 + rand(2)); /* Either -1 or -2 */

/* 3. Calculate Image Coordinates (Centre of enlargement is [0,0]) */
/* Rule: (x, y) -> (k*x, k*y) */
pA: [x1, y1];
pB: [x2, y2];
pC: [x3, y3];

pA_prime: [sf*x1, sf*y1];
pB_prime: [sf*x2, sf*y2];
pC_prime: [sf*x3, sf*y3];
